DELETE FROM MUIPROMO.ACL;
DELETE FROM MUIPROMO.UI;
DROP SEQUENCE MUIPROMO.UI_SEQ;
DROP SEQUENCE MUIPROMO.ACL_SEQ;
SET DEFINE OFF;




CREATE SEQUENCE MUIPROMO.ACL_SEQ
    MINVALUE 1
    MAXVALUE 2147483647
    START WITH 170
    INCREMENT BY 1;

SELECT MUIPROMO.ACL_SEQ.nextval FROM dual;

CREATE SEQUENCE MUIPROMO.UI_SEQ
    MINVALUE 1
    MAXVALUE 2147483647
    START WITH 25
    INCREMENT BY 1;

SELECT MUIPROMO.UI_SEQ.nextval FROM dual;

